prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?msgFlow ?msgFlowName ?msgSourceRef ?msgTargetRef ?msgRef ?messageName WHERE {
  # Get the choreography this EndEvent belongs to
  <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-0BE830A0-AD6C-48D3-BE6D-7E8E4D1852EE> tai:belongsTo ?choreo .

  # Find MessageFlows in the same choreography that reference this EndEvent's ID
  ?msgFlow a bboExt:MessageFlow .
  ?msgFlow tai:belongsTo ?choreo .
  OPTIONAL { ?msgFlow bbo:name ?msgFlowName . }
  OPTIONAL { ?msgFlow bboExt:sourceRef ?msgSourceRef . }
  OPTIONAL { ?msgFlow bboExt:targetRef ?msgTargetRef . }
  OPTIONAL { ?msgFlow bboExt:messageRef ?msgRef . }
  FILTER(
    CONTAINS(STR(?msgSourceRef), "0BE830A0-AD6C-48D3-BE6D-7E8E4D1852EE") ||
    CONTAINS(STR(?msgTargetRef), "0BE830A0-AD6C-48D3-BE6D-7E8E4D1852EE")
  )
  OPTIONAL {
    ?message a bboExt:Message .
    ?message tai:belongsTo ?choreo .
    FILTER(STRENDS(STR(?message), ?msgRef))
    ?message bbo:name ?messageName .
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?msgFlow ?msgFlowName ?srcRef ?tgtRef ?msgRef WHERE {
  <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-0BE830A0-AD6C-48D3-BE6D-7E8E4D1852EE> tai:belongsTo ?choreo .
  ?msgFlow a bboExt:MessageFlow .
  ?msgFlow tai:belongsTo ?choreo .
  OPTIONAL { ?msgFlow bbo:name ?msgFlowName . }
  OPTIONAL { ?msgFlow bboExt:sourceRef ?srcRef . }
  OPTIONAL { ?msgFlow bboExt:targetRef ?tgtRef . }
  OPTIONAL { ?msgFlow bboExt:messageRef ?msgRef . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?message ?messageName ?messageId WHERE {
  <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-0BE830A0-AD6C-48D3-BE6D-7E8E4D1852EE> tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?def .
  ?message a bboExt:Message .
  {
    ?message tai:belongsTo ?choreo .
  } UNION {
    ?message tai:belongsTo ?def .
  }
  OPTIONAL { ?message bbo:name ?messageName . }
  OPTIONAL { ?message bbo:id ?messageId . }
}
LIMIT 25
